import{_ as l,o as e,c as i,ag as a}from"./chunks/framework.CKZNj4UW.js";const g=JSON.parse('{"title":"支持的文件类型","description":"","frontmatter":{},"headers":[],"relativePath":"guide/supported-types.md","filePath":"guide/supported-types.md"}'),d={name:"guide/supported-types.md"};function r(t,o,c,n,s,h){return e(),i("div",null,[...o[0]||(o[0]=[a('<h1 id="支持的文件类型" tabindex="-1">支持的文件类型 <a class="header-anchor" href="#支持的文件类型" aria-label="Permalink to &quot;支持的文件类型&quot;">​</a></h1><p>React File Preview 支持多种常见的文件格式预览。</p><h2 id="图片格式" tabindex="-1">图片格式 <a class="header-anchor" href="#图片格式" aria-label="Permalink to &quot;图片格式&quot;">​</a></h2><p>支持所有浏览器原生支持的图片格式：</p><ul><li><strong>JPEG/JPG</strong> - <code>.jpg</code>, <code>.jpeg</code></li><li><strong>PNG</strong> - <code>.png</code></li><li><strong>GIF</strong> - <code>.gif</code> (支持动画)</li><li><strong>WebP</strong> - <code>.webp</code></li><li><strong>SVG</strong> - <code>.svg</code></li><li><strong>BMP</strong> - <code>.bmp</code></li><li><strong>ICO</strong> - <code>.ico</code></li></ul><h3 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>缩放和平移（范围 0.01x - 10x）</li><li>旋转（顺时针/逆时针 90°）</li><li>鼠标滚轮缩放</li><li>拖拽移动</li></ul><h2 id="视频格式" tabindex="-1">视频格式 <a class="header-anchor" href="#视频格式" aria-label="Permalink to &quot;视频格式&quot;">​</a></h2><p>支持 HTML5 视频格式：</p><ul><li><strong>MP4</strong> - <code>.mp4</code></li><li><strong>WebM</strong> - <code>.webm</code></li><li><strong>OGG</strong> - <code>.ogg</code>, <code>.ogv</code></li><li><strong>MOV</strong> - <code>.mov</code></li><li><strong>AVI</strong> - <code>.avi</code></li><li><strong>MKV</strong> - <code>.mkv</code></li><li><strong>M4V</strong> - <code>.m4v</code></li><li><strong>3GP</strong> - <code>.3gp</code></li><li><strong>FLV</strong> - <code>.flv</code></li></ul><h3 id="特性-1" tabindex="-1">特性 <a class="header-anchor" href="#特性-1" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>基于 Video.js 播放器</li><li>播放/暂停控制</li><li>音量调节</li><li>进度条</li><li>全屏播放</li></ul><h2 id="音频格式" tabindex="-1">音频格式 <a class="header-anchor" href="#音频格式" aria-label="Permalink to &quot;音频格式&quot;">​</a></h2><p>支持 HTML5 音频格式：</p><ul><li><strong>MP3</strong> - <code>.mp3</code></li><li><strong>WAV</strong> - <code>.wav</code></li><li><strong>OGG</strong> - <code>.ogg</code></li><li><strong>M4A</strong> - <code>.m4a</code></li><li><strong>AAC</strong> - <code>.aac</code></li><li><strong>FLAC</strong> - <code>.flac</code></li></ul><h3 id="特性-2" tabindex="-1">特性 <a class="header-anchor" href="#特性-2" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>播放/暂停控制</li><li>音量调节</li><li>进度条</li><li>快进/快退（±10 秒）</li></ul><h2 id="pdf-文档" tabindex="-1">PDF 文档 <a class="header-anchor" href="#pdf-文档" aria-label="Permalink to &quot;PDF 文档&quot;">​</a></h2><ul><li><strong>PDF</strong> - <code>.pdf</code></li></ul><h3 id="特性-3" tabindex="-1">特性 <a class="header-anchor" href="#特性-3" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>页面导航（上一页/下一页）</li><li>缩放控制（0.01x - 10x）</li><li>连续滚动浏览</li><li>页码显示</li></ul><h2 id="office-文档" tabindex="-1">Office 文档 <a class="header-anchor" href="#office-文档" aria-label="Permalink to &quot;Office 文档&quot;">​</a></h2><h3 id="word-文档" tabindex="-1">Word 文档 <a class="header-anchor" href="#word-文档" aria-label="Permalink to &quot;Word 文档&quot;">​</a></h3><ul><li><strong>DOCX</strong> - <code>.docx</code></li></ul><h3 id="excel-表格" tabindex="-1">Excel 表格 <a class="header-anchor" href="#excel-表格" aria-label="Permalink to &quot;Excel 表格&quot;">​</a></h3><ul><li><strong>XLSX</strong> - <code>.xlsx</code></li></ul><h3 id="powerpoint-演示文稿" tabindex="-1">PowerPoint 演示文稿 <a class="header-anchor" href="#powerpoint-演示文稿" aria-label="Permalink to &quot;PowerPoint 演示文稿&quot;">​</a></h3><ul><li><strong>PPTX</strong> - <code>.pptx</code></li><li><strong>PPT</strong> - <code>.ppt</code></li></ul><h3 id="特性-4" tabindex="-1">特性 <a class="header-anchor" href="#特性-4" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>保留原始格式</li><li>支持图片和表格</li><li>响应式布局</li><li>显示所有工作表（Excel）</li><li>平铺/幻灯片两种显示模式（PowerPoint，16:9 宽高比）</li></ul><h2 id="outlook-邮件" tabindex="-1">Outlook 邮件 <a class="header-anchor" href="#outlook-邮件" aria-label="Permalink to &quot;Outlook 邮件&quot;">​</a></h2><ul><li><strong>MSG</strong> - <code>.msg</code></li></ul><h3 id="特性-5" tabindex="-1">特性 <a class="header-anchor" href="#特性-5" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>解析邮件头信息（发件人、收件人、主题、日期）</li><li>邮件正文渲染</li><li>附件列表展示</li></ul><h2 id="电子书" tabindex="-1">电子书 <a class="header-anchor" href="#电子书" aria-label="Permalink to &quot;电子书&quot;">​</a></h2><ul><li><strong>EPUB</strong> - <code>.epub</code></li></ul><h3 id="特性-6" tabindex="-1">特性 <a class="header-anchor" href="#特性-6" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>基于 epub.js 渲染</li><li>左右翻页（按钮 / 键盘方向键）</li><li>章节自动分页与页码显示</li><li>自适应屏幕宽度</li></ul><h2 id="markdown-文档" tabindex="-1">Markdown 文档 <a class="header-anchor" href="#markdown-文档" aria-label="Permalink to &quot;Markdown 文档&quot;">​</a></h2><ul><li><strong>Markdown</strong> - <code>.md</code>, <code>.markdown</code></li></ul><h3 id="特性-7" tabindex="-1">特性 <a class="header-anchor" href="#特性-7" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>GitHub Flavored Markdown (GFM) 支持</li><li>代码语法高亮</li><li>表格支持</li><li>任务列表</li><li>自动链接</li></ul><h2 id="代码文件" tabindex="-1">代码文件 <a class="header-anchor" href="#代码文件" aria-label="Permalink to &quot;代码文件&quot;">​</a></h2><p>支持 40+ 种编程语言的语法高亮：</p><ul><li><strong>JavaScript/TypeScript</strong> - <code>.js</code>, <code>.jsx</code>, <code>.ts</code>, <code>.tsx</code></li><li><strong>Python</strong> - <code>.py</code></li><li><strong>Java</strong> - <code>.java</code></li><li><strong>C/C++</strong> - <code>.c</code>, <code>.cpp</code>, <code>.h</code></li><li><strong>C#</strong> - <code>.cs</code></li><li><strong>Go</strong> - <code>.go</code>, <code>.mod</code></li><li><strong>Rust</strong> - <code>.rs</code></li><li><strong>Lua</strong> - <code>.lua</code></li><li><strong>Vim Script</strong> - <code>.vim</code></li><li><strong>PHP</strong> - <code>.php</code></li><li><strong>Ruby</strong> - <code>.rb</code></li><li><strong>Swift</strong> - <code>.swift</code></li><li><strong>Kotlin</strong> - <code>.kt</code></li><li><strong>HTML</strong> - <code>.html</code></li><li><strong>CSS/SCSS/Sass/Less</strong> - <code>.css</code>, <code>.scss</code>, <code>.sass</code>, <code>.less</code></li><li><strong>YAML</strong> - <code>.yaml</code>, <code>.yml</code></li><li><strong>TOML</strong> - <code>.toml</code></li><li><strong>INI</strong> - <code>.ini</code>, <code>.conf</code>, <code>.env</code></li><li><strong>Lock 文件</strong> - <code>.lock</code></li><li><strong>Diff/Patch</strong> - <code>.diff</code>, <code>.patch</code></li><li><strong>Shell</strong> - <code>.sh</code>, <code>.bash</code>, <code>.zsh</code></li><li><strong>SQL</strong> - <code>.sql</code></li><li><strong>Log</strong> - <code>.log</code></li></ul><h3 id="特性-8" tabindex="-1">特性 <a class="header-anchor" href="#特性-8" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>语法高亮（VS Code Dark+ 主题）</li><li>自动语言检测</li><li>行号显示</li></ul><h2 id="csv-tsv-表格" tabindex="-1">CSV / TSV 表格 <a class="header-anchor" href="#csv-tsv-表格" aria-label="Permalink to &quot;CSV / TSV 表格&quot;">​</a></h2><ul><li><strong>CSV</strong> - <code>.csv</code></li><li><strong>TSV</strong> - <code>.tsv</code></li></ul><h3 id="特性-9" tabindex="-1">特性 <a class="header-anchor" href="#特性-9" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>纯前端解析，无第三方依赖</li><li>支持 RFC 4180 双引号转义与字段内换行</li><li>表格式渲染，首行自动识别为表头</li><li>显示行数/列数统计</li></ul><h2 id="xml" tabindex="-1">XML <a class="header-anchor" href="#xml" aria-label="Permalink to &quot;XML&quot;">​</a></h2><ul><li><strong>XML</strong> - <code>.xml</code></li></ul><h3 id="特性-10" tabindex="-1">特性 <a class="header-anchor" href="#特性-10" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>使用浏览器原生 <code>DOMParser</code> 做格式校验</li><li>自动缩进美化</li><li>语法高亮</li></ul><h2 id="字幕-歌词文件" tabindex="-1">字幕 / 歌词文件 <a class="header-anchor" href="#字幕-歌词文件" aria-label="Permalink to &quot;字幕 / 歌词文件&quot;">​</a></h2><ul><li><strong>SRT</strong> - <code>.srt</code></li><li><strong>WebVTT</strong> - <code>.vtt</code></li><li><strong>LRC</strong> - <code>.lrc</code>（基础歌词，<code>[mm:ss.xx]</code> 行时间戳，支持 <code>[ti:][ar:][al:]</code> 等元数据）</li><li><strong>Enhanced LRC</strong> - <code>.elrc</code>（增强歌词，行内 <code>&lt;mm:ss.xx&gt;</code> 逐字时间戳）</li><li><strong>ASS / SSA</strong> - <code>.ass</code> / <code>.ssa</code>（Advanced SubStation Alpha，自动剥离 <code>\\N</code> <code>\\h</code> 与 <code>{...}</code> 样式覆盖码）</li><li><strong>TTML / DFXP</strong> - <code>.ttml</code> / <code>.dfxp</code>（W3C / Apple Music 使用的 XML 字幕，支持 <code>begin</code> / <code>end</code> / <code>dur</code> 与 <code>&lt;br/&gt;</code>）</li></ul><h3 id="特性-11" tabindex="-1">特性 <a class="header-anchor" href="#特性-11" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>纯前端解析，零第三方依赖</li><li>自动按内容/扩展名识别格式</li><li>结构化 cue 列表展示（索引、时间区间、文本）</li><li>LRC / ELRC 自动展示元数据（标题 / 艺术家 / 专辑 / 偏移……）</li><li>ELRC 逐字时间戳以词条形式排列展示</li><li>ASS / SSA 同步显示 Style 标签，自动应用 <code>offset</code> 偏移</li></ul><h2 id="json" tabindex="-1">JSON <a class="header-anchor" href="#json" aria-label="Permalink to &quot;JSON&quot;">​</a></h2><ul><li><strong>JSON</strong> - <code>.json</code></li></ul><h3 id="特性-12" tabindex="-1">特性 <a class="header-anchor" href="#特性-12" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>自动格式化缩进</li><li>语法高亮</li></ul><h2 id="zip-压缩包" tabindex="-1">ZIP 压缩包 <a class="header-anchor" href="#zip-压缩包" aria-label="Permalink to &quot;ZIP 压缩包&quot;">​</a></h2><ul><li><strong>ZIP</strong> - <code>.zip</code></li></ul><h3 id="特性-13" tabindex="-1">特性 <a class="header-anchor" href="#特性-13" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>基于 JSZip 解析压缩包目录结构</li><li>左侧树形目录 + 右侧内嵌预览</li><li>内嵌预览文本、代码（带高亮）与图片</li><li>其他类型可通过&quot;下载&quot;按钮导出为独立文件</li></ul><h2 id="纯文本" tabindex="-1">纯文本 <a class="header-anchor" href="#纯文本" aria-label="Permalink to &quot;纯文本&quot;">​</a></h2><ul><li><strong>TXT</strong> - <code>.txt</code></li><li>其他未识别的文本文件</li></ul><h2 id="不支持的格式" tabindex="-1">不支持的格式 <a class="header-anchor" href="#不支持的格式" aria-label="Permalink to &quot;不支持的格式&quot;">​</a></h2><p>对于不支持的文件格式，组件会显示一个友好的提示界面，包含：</p><ul><li>文件名和大小</li><li>下载按钮</li><li>文件类型说明</li></ul><h2 id="文件类型检测" tabindex="-1">文件类型检测 <a class="header-anchor" href="#文件类型检测" aria-label="Permalink to &quot;文件类型检测&quot;">​</a></h2><p>组件会按以下优先级检测文件类型：</p><ol><li><strong>MIME 类型</strong>：如果提供了 <code>type</code> 属性，优先使用</li><li><strong>文件扩展名</strong>：从文件名自动推断 MIME 类型</li><li><strong>默认类型</strong>：无法识别时标记为 <code>unsupported</code></li></ol><p>支持的文件类型枚举：</p><ul><li><code>image</code> - 图片文件</li><li><code>pdf</code> - PDF 文档</li><li><code>docx</code> - Word 文档</li><li><code>xlsx</code> - Excel 表格</li><li><code>pptx</code> - PowerPoint 演示文稿</li><li><code>msg</code> - Outlook 邮件</li><li><code>epub</code> - EPUB 电子书</li><li><code>video</code> - 视频文件</li><li><code>audio</code> - 音频文件</li><li><code>markdown</code> - Markdown 文件</li><li><code>json</code> - JSON 文件</li><li><code>csv</code> - CSV/TSV 文件</li><li><code>xml</code> - XML 文件</li><li><code>subtitle</code> - SRT / VTT / LRC / ELRC / ASS / SSA / TTML 字幕与歌词文件</li><li><code>zip</code> - ZIP 压缩包</li><li><code>text</code> - 其他文本和代码文件</li><li><code>unsupported</code> - 不支持的类型</li></ul>',77)])])}const p=l(d,[["render",r]]);export{g as __pageData,p as default};
